<?php require_once __DIR__ . '/app/auth.php'; require_login(); $pdo=db(); $id=(int)($_GET['id']??0); $st=$pdo->prepare('SELECT pay.*,c.name customer_name,c.customer_code,c.address,c.phone,p.name package_name FROM payments pay JOIN customers c ON c.id=pay.customer_id LEFT JOIN packages p ON p.id=c.package_id WHERE pay.id=?'); $st->execute([$id]); $r=$st->fetch(); if(!$r){http_response_code(404); exit('Kwitansi tidak ditemukan');} ?>
<!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Kwitansi <?=e($r['payment_code'])?></title><style>body{font-family:Arial,sans-serif;background:#f8fafc;color:#111827}.receipt{max-width:760px;margin:30px auto;background:white;border-radius:24px;padding:32px;box-shadow:0 20px 60px rgba(15,23,42,.12)}.head{display:flex;justify-content:space-between;gap:16px;border-bottom:2px solid #e5e7eb;padding-bottom:18px}.logo{font-size:26px;font-weight:900;color:#2563eb}.row{display:flex;justify-content:space-between;border-bottom:1px dashed #d1d5db;padding:12px 0}.total{font-size:28px;font-weight:900;color:#047857}.btn{display:inline-block;margin-top:22px;padding:12px 16px;border-radius:12px;background:#2563eb;color:white;text-decoration:none;font-weight:800}@media print{body{background:white}.receipt{box-shadow:none;margin:0}.btn{display:none}}</style></head><body><main class="receipt"><div class="head"><div><div class="logo">Dentanet Billing</div><p>Denta Sejahtera Group</p></div><div><b>KWITANSI</b><br><?=e($r['payment_code'])?></div></div><h2>Pembayaran Tagihan Internet</h2><div class="row"><span>ID Pelanggan</span><b><?=e($r['customer_code'])?></b></div><div class="row"><span>Nama</span><b><?=e($r['customer_name'])?></b></div><div class="row"><span>Paket</span><b><?=e($r['package_name']??'-')?></b></div><div class="row"><span>Bulan Tagihan</span><b><?=e($r['invoice_month'])?></b></div><div class="row"><span>Tanggal Bayar</span><b><?=e($r['paid_at'])?></b></div><div class="row"><span>Metode</span><b><?=e($r['method'])?></b></div><p>Total dibayar</p><div class="total"><?=rupiah($r['amount'])?></div><p style="margin-top:28px;color:#64748b">Dicetak oleh <?=e($_SESSION['user']['name']??'Admin')?> pada <?=date('Y-m-d H:i')?></p><a class="btn" href="javascript:window.print()">Cetak Kwitansi</a></main></body></html>
